# Prompt: Build a Python function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os

def delete_file(filename):
    # Get the absolute path of the uploads directory
    uploads_dir = os.path.abspath('uploads')
    
    # Join the uploads directory with the filename to get the full file path
    file_path = os.path.join(uploads_dir, filename)
    
    # Check if the file exists and delete it if it does
    if os.path.exists(file_path):
        os.remove(file_path)